/**
 * Finds a specific JSX attribute by name in a JSX element.
 *
 * This is useful for validating specific props/attributes on JSX components.
 *
 * For example:
 * <Image src="https://example.com/image.png" alt="Example" />
 *
 * Calling findJSXAttribute(node, 'src') would return the JSXAttribute node for the src attribute.
 *
 * @param node - The JSXOpeningElement AST node
 * @param attributeName - The name of the attribute to find
 * @returns The JSXAttribute node if found, or null if not found
 */
export const findJSXAttribute = (node, attributeName) => {
    for (const attribute of node.attributes) {
        if (attribute.type === 'JSXAttribute' &&
            attribute.name.type === 'JSXIdentifier' &&
            attribute.name.name === attributeName) {
            return attribute;
        }
    }
    return null;
};
/**
 * Checks if a JSX element is a specific component by name.
 *
 * This is useful for rules that need to validate specific component usage.
 *
 * For example:
 * <Image src="..." /> would return true when checking for 'Image'
 * <div /> would return false when checking for 'Image'
 *
 * @param node - The JSXOpeningElement AST node
 * @param componentName - The name of the component to check for
 * @returns True if the element is the specified component, false otherwise
 */
export const isJSXComponent = (node, componentName) => {
    return node.name.type === 'JSXIdentifier' && node.name.name === componentName;
};
